#!/usr/bin/env python3
"""
Compile all experiment results into _Results/experiment_result.md.
"""

import argparse
import sys
from pathlib import Path

sys.path.insert(0, str(Path(__file__).parent.parent))


def main():
    parser = argparse.ArgumentParser(description="Compile All Results")
    parser.add_argument("--results-dir", default="_Results")
    args = parser.parse_args()

    results_dir = Path(args.results_dir)
    output_file = results_dir / "experiment_result.md"

    lines = [
        "# CRA Experiment Results (Compiled)",
        "",
        "> Auto-generated by scripts/compile_results.py",
        "",
    ]

    # Collect all .md files from subdirectories
    sections = [
        ("Probe", "probe"),
        ("Pilot 2x2", "pilot"),
        ("Benchmark", "benchmark"),
        ("2x2 Ablation", "ablation"),
        ("LoRA vs Full-FT", "lora_vs_ft"),
        ("MAGIC Feasibility", "magic"),
        ("Scale-up", "scaleup"),
    ]

    for title, subdir in sections:
        section_dir = results_dir / subdir
        if section_dir.exists():
            md_files = sorted(section_dir.glob("*.md"))
            if md_files:
                lines.append(f"---")
                lines.append(f"")
                lines.append(f"# {title}")
                lines.append("")
                for md_file in md_files:
                    content = md_file.read_text().strip()
                    # Demote headers by one level
                    for line in content.split("\n"):
                        if line.startswith("#"):
                            lines.append("#" + line)  # add one more #
                        else:
                            lines.append(line)
                    lines.append("")

    with open(output_file, "w") as f:
        f.write("\n".join(lines))

    print(f"Compiled results: {output_file}")


if __name__ == "__main__":
    main()
